$(function () {
  var $wrapper = $("#main-wrapper");
  var desktopBreakpoint = 1199;

  function isMobileLayout() {
    return window.innerWidth <= desktopBreakpoint;
  }

  function closeSidebar() {
    $wrapper.removeClass("show-sidebar");
    $(".sidebar-backdrop").removeClass("show");
  }

  function openSidebar() {
    $wrapper.addClass("show-sidebar");
    $(".sidebar-backdrop").addClass("show");
  }

  function syncSidebarMode() {
    if (!$wrapper.length) {
      return;
    }

    if (!$(".sidebar-backdrop").length) {
      $("body").append('<div class="sidebar-backdrop" aria-hidden="true"></div>');
    }

    if (isMobileLayout()) {
      $wrapper.attr("data-sidebartype", "mini-sidebar").addClass("mini-sidebar");
    } else {
      $wrapper.attr("data-sidebartype", "full").removeClass("mini-sidebar show-sidebar");
      $(".sidebar-backdrop").removeClass("show");
    }
  }

  syncSidebarMode();
  $(window).on("resize", syncSidebarMode);

  $(document).on("click", ".sidebartoggler, #headerCollapse", function () {
    if (isMobileLayout()) {
      if ($wrapper.hasClass("show-sidebar")) {
        closeSidebar();
      } else {
        openSidebar();
      }
      return;
    }

    $wrapper.toggleClass("mini-sidebar");
    $wrapper.attr("data-sidebartype", $wrapper.hasClass("mini-sidebar") ? "mini-sidebar" : "full");
  });

  $(document).on("click", ".sidebar-backdrop", closeSidebar);

  $(document).on("click", "#sidebarnav a", function () {
    if (isMobileLayout()) {
      closeSidebar();
    }
  });

  function ensureConfirmModal() {
    var $modal = $("#hostelConfirmModal");

    if ($modal.length) {
      return $modal;
    }

    $("body").append(
      '<div class="modal fade" id="hostelConfirmModal" tabindex="-1" aria-hidden="true">' +
        '<div class="modal-dialog modal-dialog-centered">' +
          '<div class="modal-content">' +
            '<div class="modal-header">' +
              '<h5 class="modal-title">Confirm action</h5>' +
              '<button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>' +
            '</div>' +
            '<div class="modal-body text-muted"></div>' +
            '<div class="modal-footer">' +
              '<button type="button" class="btn btn-light" data-bs-dismiss="modal">Cancel</button>' +
              '<button type="button" class="btn btn-primary" id="hostelConfirmProceed">Continue</button>' +
            '</div>' +
          '</div>' +
        '</div>' +
      '</div>'
    );

    return $("#hostelConfirmModal");
  }

  $(document).on("click", "button[data-confirm-message]", function (event) {
    var button = this;
    var form = button.form;

    if (!form) {
      return;
    }

    if (form.checkValidity && !form.checkValidity()) {
      return;
    }

    event.preventDefault();

    var $modal = ensureConfirmModal();
    var modal = bootstrap.Modal.getOrCreateInstance($modal[0]);
    $modal.find(".modal-body").text(button.getAttribute("data-confirm-message"));
    $modal.find("#hostelConfirmProceed").off("click").on("click", function () {
      if (button.name) {
        $("<input>", {
          type: "hidden",
          name: button.name,
          value: button.value || ""
        }).appendTo(form);
      }

      modal.hide();
      HTMLFormElement.prototype.submit.call(form);
    });
    modal.show();
  });

  $(document).on("submit", "form", function () {
    var $button = $(this).find('button[type="submit"][name]:focus, button[type="submit"]:focus').first();

    if (!$button.length || $button.data("loading") === false) {
      return;
    }

    if ($button.attr("name")) {
      $("<input>", {
        type: "hidden",
        name: $button.attr("name"),
        value: $button.val() || ""
      }).appendTo(this);
    }

    var originalHtml = $button.html();
    $button.data("original-html", originalHtml).prop("disabled", true);
    $button.html('<span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>Processing');
  });
});
